// Script: generar_177_evoluciones_editar_eliminar.js
// Arreglos en Observaciones (Prevención):
//
// 1) MODALES DUPLICADOS eliminados — había DOS modales de "Nueva evolución"
//    y DOS de "Marcar como resuelta" renderizando al mismo tiempo.
//    Queda solo la versión nueva de cada uno.
//
// 2) editarEvo(evo, obsId) — botón ✏️ en cada evolución del timeline.
//    Abre el mismo modal con fecha y nota precargadas. Al guardar
//    actualiza la evolución existente (y reemplaza foto si eliges una nueva).
//
// 3) eliminarEvo(evo, obsId) — botón 🗑️ con confirmación.
//    Borra la evolución y su foto del storage (fotos-salud).
//
// 4) ENTRADA INICIAL integrada al timeline — la foto/nota original de la
//    observación (fecha_inicio) ahora aparece DENTRO del timeline en su
//    posición cronológica correcta, marcada como "· Inicio" con punto
//    naranja (#CD7421). Ya no queda separada arriba, y la foto principal
//    no se duplica al expandir.
//
// 5) FOTOS con object-contain y max-h-64 — las heridas ya no se cortan.
//
// SOLO toca app/prevencion/page.tsx (no pisa los cambios 173-176 de
// registro diario, calendario ni dispensador).

const fs = require('fs'); const path = require('path');
function tsx(r, b64) {
  const f = path.join(...r.split('/'));
  const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true });
  fs.writeFileSync(f, Buffer.from(b64,'base64').toString('utf8'));
  console.log('OK: ' + f);
}
tsx('app/prevencion/page.tsx', "");
